class MinStack {
public:
    MinStack() {}

    void push(int val) {
        stack_.push(val);
        min_stack_.push(val);
    }

    void pop() {
        if (min_stack_.empty()) {
            stack_.pop();
        } else {
            int min_val = min_stack_.top();
            min_stack_.pop();
            stack_.push(min_val);
        }
    }

    int top() {
        if (min_stack_.empty()) {
            return stack_.top();
        } else {
            return min_stack_.top();
        }
    }

    int getMin() {
        return min_stack_.top();
    }

    vector<int> min_stack_;
    vector<int> stack_;
};
